/**
 * MedX keyboard accessibility runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Keyboard navigation handlers for menus.
 */
const KEYBOARD_TOKENS = Object.freeze({
  primary: { value: "a11y-keyboard-primary", scope: "a11y" },
  secondary: { value: "a11y-keyboard-secondary", scope: "a11y" },
  muted: { value: "a11y-keyboard-muted", scope: "a11y" },
  accent: { value: "a11y-keyboard-accent", scope: "a11y" },
  surface: { value: "a11y-keyboard-surface", scope: "a11y" },
});

const KEYBOARD_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const KEYBOARD_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const keyboardRegistry = new Map();
const KEYBOARD_listeners = new Set();
let KEYBOARD_seq = 0;

function createKeyboardId(prefix = "medx-a11y-keyboard") {
  KEYBOARD_seq += 1;
  return `${prefix}-${KEYBOARD_seq}`;
}

function registerKeyboard(config = {}) {
  const entryId = config.id ?? createKeyboardId();
  const preset = KEYBOARD_PRESETS[config.preset ?? "default"] ?? KEYBOARD_PRESETS.default;
  const token = KEYBOARD_TOKENS[config.token ?? preset.token] ?? KEYBOARD_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: KEYBOARD_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  keyboardRegistry.set(entryId, entry);
  notifyKeyboardListeners("register", entry);
  return entry;
}

function updateKeyboard(id, patch = {}) {
  const entry = keyboardRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyKeyboardListeners("update", entry);
  return entry;
}

function resolveKeyboard(id) {
  const entry = keyboardRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listKeyboardEntries(filter = {}) {
  let items = Array.from(keyboardRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onKeyboardEvent(listener) {
  KEYBOARD_listeners.add(listener);
  return () => KEYBOARD_listeners.delete(listener);
}

function notifyKeyboardListeners(type, entry) {
  for (const listener of KEYBOARD_listeners) {
    try {
      listener({ type, entry, registrySize: keyboardRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:a11y:keyboard] listener error", err.message);
    }
  }
}

function getKeyboardMetrics() {
  const items = listKeyboardEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(KEYBOARD_TOKENS).length,
    presets: Object.keys(KEYBOARD_PRESETS).length,
  };
}

async function runMedxKeyboard() {
  console.log("[medx:ui:a11y:keyboard] runtime initialized");
  console.log(`[medx:ui:a11y:keyboard] tokens=${Object.keys(KEYBOARD_TOKENS).length} presets=${Object.keys(KEYBOARD_PRESETS).length}`);

  const events = [];
  onKeyboardEvent((e) => events.push(e.type));

  const domains = Object.keys(KEYBOARD_SUPPLY_CHAIN);
  const presets = Object.keys(KEYBOARD_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerKeyboard({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "a11y/keyboard" },
    });
  }

  const first = listKeyboardEntries()[0];
  if (first) updateKeyboard(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getKeyboardMetrics();
  const resolved = first ? resolveKeyboard(first.id) : null;

  console.log(`[medx:ui:a11y:keyboard] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:a11y:keyboard] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:a11y:keyboard] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:a11y:keyboard] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:a11y:keyboard] bootstrap complete");
}

module.exports = runMedxKeyboard;
